package com.company.traceuploader.commit;
import com.company.traceuploader.config.AgentConfig;import com.company.traceuploader.hdfs.LocalFsHdfsClient;import com.company.traceuploader.manifest.LocalJsonlManifestWriter;import com.company.traceuploader.metadata.*;import com.company.traceuploader.model.TraceFileMetadata;import com.company.traceuploader.scanner.SealedFile;import com.company.traceuploader.state.*;import org.junit.jupiter.api.*;import java.nio.file.*;import static org.junit.jupiter.api.Assertions.*;
class LocalFsCommitProtocolTest { @TempDir Path dir;
 TraceFileMetadata meta(AgentConfig c) throws Exception { Path f=dir.resolve("trace-payment-dev-local-c1-host001-pid123-bootlocal-20260610T100000-20260610T100500-seq000001.jsonl"); if(!Files.exists(f)) Files.writeString(f,"one\ntwo\n"); Path d=dir.resolve(f.getFileName()+".done"); if(!Files.exists(d)) Files.createFile(d); return new MetadataService(c,new ChecksumService(),new FileIdGenerator()).build(new SealedFile(f,d),1); }
 @Test void commitsViaStagingThenFinalAndIsIdempotent() throws Exception { AgentConfig c=new AgentConfig(); c.hdfs.localRootForTesting=dir.resolve("hdfs").toString(); c.manifest.localPath=dir.resolve("state/manifest.jsonl").toString(); c.hdfs.bucketCount=16; TraceFileMetadata m=meta(c); try(JsonlWalUploadStateStore store=new JsonlWalUploadStateStore(dir.resolve("state/wal.jsonl"))){ store.upsert(UploadFileRecordFactory.fromMetadata(m,UploadState.DISCOVERED,0)); LocalFsCommitProtocol p=new LocalFsCommitProtocol(new LocalFsHdfsClient(Path.of(c.hdfs.localRootForTesting)),store,new LocalJsonlManifestWriter(Path.of(c.manifest.localPath),c),c); assertEquals(UploadState.MANIFEST_COMMITTED,p.commit(m).state()); assertTrue(Files.exists(Path.of(c.hdfs.localRootForTesting).resolve(m.hdfsFinalPath().substring(1)))); assertFalse(Files.exists(Path.of(c.hdfs.localRootForTesting).resolve(m.hdfsStagingPath().substring(1)))); assertEquals(UploadState.MANIFEST_COMMITTED,p.commit(m).state()); assertEquals(1, Files.readAllLines(Path.of(c.manifest.localPath)).size()); } }
 @Test void quarantinesWhenFinalExistsWithDifferentContent() throws Exception { AgentConfig c=new AgentConfig(); c.hdfs.localRootForTesting=dir.resolve("hdfs2").toString(); c.manifest.localPath=dir.resolve("state2/manifest.jsonl").toString(); TraceFileMetadata m=meta(c); LocalFsHdfsClient hdfs=new LocalFsHdfsClient(Path.of(c.hdfs.localRootForTesting)); Path finalLocal=hdfs.toLocalPath(m.hdfsFinalPath()); Files.createDirectories(finalLocal.getParent()); Files.writeString(finalLocal,"different"); try(JsonlWalUploadStateStore store=new JsonlWalUploadStateStore(dir.resolve("state2/wal.jsonl"))){ store.upsert(UploadFileRecordFactory.fromMetadata(m,UploadState.DISCOVERED,0)); LocalFsCommitProtocol p=new LocalFsCommitProtocol(hdfs,store,new LocalJsonlManifestWriter(Path.of(c.manifest.localPath),c),c); assertEquals(UploadState.QUARANTINED,p.commit(m).state()); assertEquals("different",Files.readString(finalLocal)); } }
}
